New Row.code:
// Insert a row into a SQL Server table.
insert(
  'users',
  { name: 'Elodie', email: 'elodie@example.org', age: 31 },
  { writeSql: true }
);

Update Row.code:
// Update a row using a parameterised query.
// In mssql, named parameters use @-prefixed placeholders.
sql({
  query: 'UPDATE users SET email = @email WHERE id = @id;',
  params: { email: $.data.email, id: $.data.id },
  writeSql: true,
});

Find Row.code:
// Fetch a single value from a row matched by an equality filter.
findValue({
  uuid: 'id',
  relation: 'users',
  where: { email: $.data.email },
});

Find Row via Custom Query.code:
// Run a custom SELECT returning a single row.
sql({
  query: 'SELECT TOP 1 * FROM users WHERE email = @email;',
  params: { email: $.data.email },
});

Find Rows via Custom Query.code:
// Run a custom SELECT returning many rows.
sql({
  query: 'SELECT id, name, email FROM users WHERE created_at > @since ORDER BY id;',
  params: { since: '2026-01-01' },
});
